package org.eclipse.rdf4j.sail.base;

import org.slf4j.Logger;

final class SketchEstimatorMemoryMonitor implements AutoCloseable {

	interface EvictionController {
		void enforceResidentCeiling();

		int evictLruBatch(int batchSize);

		int activeLoadedBucketCount();
	}

	private final SketchEstimatorMemoryProbe memoryProbe;
	private final SketchEstimatorMemoryPolicy memoryPolicy;
	private final EvictionController evictionController;
	private final Logger logger;
	private volatile boolean closed;
	private Thread thread;

	SketchEstimatorMemoryMonitor(SketchEstimatorMemoryProbe memoryProbe, SketchEstimatorMemoryPolicy memoryPolicy,
			EvictionController evictionController, Logger logger) {
		this.memoryProbe = memoryProbe;
		this.memoryPolicy = memoryPolicy;
		this.evictionController = evictionController;
		this.logger = logger;
	}

	synchronized void start() {
		if (thread != null) {
			return;
		}
		thread = Thread.ofPlatform()
				.name("RdfJoinEstimator-MemoryMonitor")
				.daemon(true)
				.start(this::run);
	}

	@Override
	public synchronized void close() {
		closed = true;
		Thread monitor = thread;
		if (monitor != null) {
			monitor.interrupt();
		}
		thread = null;
	}

	private void run() {
		while (!closed) {
			try {
				checkMemory();
				Thread.sleep(memoryPolicy.memoryMonitorIntervalMillis);
			} catch (InterruptedException e) {
				Thread.currentThread().interrupt();
				return;
			} catch (Throwable t) {
				logger.debug("Join estimator memory monitor iteration failed", t);
			}
		}
	}

	void checkMemory() {
		double heapPressure = (double) memoryProbe.usedHeapBytes() / Math.max(1L, memoryProbe.maxMemoryBytes());
//		if (heapPressure > 0.5) {
//		System.out.println("Heap pressure: " + (int) (heapPressure * 100) + "%");
//		}
		if (heapPressure < memoryPolicy.highMemoryPressurePercent) {
			evictionController.enforceResidentCeiling();
			return;
		}
		int floor = (int) Math.ceil(memoryPolicy.bucketCount * memoryPolicy.loadedBucketFloorPercent);
		while (!closed && heapPressure >= memoryPolicy.highMemoryPressurePercent
				&& evictionController.activeLoadedBucketCount() > floor) {
			int evicted = evictionController.evictLruBatch(memoryPolicy.memoryPressureUnloadBatchSize);
			System.gc();
			logger.warn(
					"High memory pressure detected ({}% used), evicted {} loaded buckets, active loaded buckets: {}, heap pressure after eviction: {}%",
					(int) (heapPressure * 100), evicted, evictionController.activeLoadedBucketCount(),
					(int) (heapPressure * 100));
			if (evicted <= 0) {
				return;
			}
			heapPressure = (double) memoryProbe.usedHeapBytes() / Math.max(1L, memoryProbe.maxMemoryBytes());
			if (heapPressure >= memoryPolicy.highMemoryPressurePercent) {
				memoryProbe.requestGc();
				heapPressure = (double) memoryProbe.usedHeapBytes() / Math.max(1L, memoryProbe.maxMemoryBytes());
			}
		}
	}
}
